#include "jayess_runtime.h"

#include <openssl/crypto.h>
#include <openssl/evp.h>
#include <openssl/hmac.h>
#include <openssl/rand.h>

#include <stddef.h>
#include <stdlib.h>
#include <string.h>

static int jayess_openssl_equal_name(const char *left, const char *right) {
    size_t i = 0;
    if (left == NULL || right == NULL) {
        return 0;
    }
    while (left[i] != '\0' && right[i] != '\0') {
        char a = left[i];
        char b = right[i];
        if (a >= 'A' && a <= 'Z') {
            a = (char)(a - 'A' + 'a');
        }
        if (b >= 'A' && b <= 'Z') {
            b = (char)(b - 'A' + 'a');
        }
        if (a != b) {
            return 0;
        }
        i++;
    }
    return left[i] == '\0' && right[i] == '\0';
}

static const EVP_MD *jayess_openssl_digest(const char *algorithm) {
    if (jayess_openssl_equal_name(algorithm, "sha1") || jayess_openssl_equal_name(algorithm, "sha-1")) {
        return EVP_sha1();
    }
    if (jayess_openssl_equal_name(algorithm, "sha256") || jayess_openssl_equal_name(algorithm, "sha-256")) {
        return EVP_sha256();
    }
    if (jayess_openssl_equal_name(algorithm, "sha384") || jayess_openssl_equal_name(algorithm, "sha-384")) {
        return EVP_sha384();
    }
    if (jayess_openssl_equal_name(algorithm, "sha512") || jayess_openssl_equal_name(algorithm, "sha-512")) {
        return EVP_sha512();
    }
    if (jayess_openssl_equal_name(algorithm, "md5")) {
        return EVP_md5();
    }
    return NULL;
}

static const EVP_CIPHER *jayess_openssl_cipher(const char *algorithm, size_t *key_length_out) {
    if (jayess_openssl_equal_name(algorithm, "aes-128-gcm")) {
        if (key_length_out != NULL) {
            *key_length_out = 16;
        }
        return EVP_aes_128_gcm();
    }
    if (jayess_openssl_equal_name(algorithm, "aes-192-gcm")) {
        if (key_length_out != NULL) {
            *key_length_out = 24;
        }
        return EVP_aes_192_gcm();
    }
    if (jayess_openssl_equal_name(algorithm, "aes-256-gcm")) {
        if (key_length_out != NULL) {
            *key_length_out = 32;
        }
        return EVP_aes_256_gcm();
    }
    return NULL;
}

static char *jayess_openssl_hex_encode(const unsigned char *bytes, size_t length) {
    static const char digits[] = "0123456789abcdef";
    char *text = (char *)malloc(length * 2 + 1);
    size_t i = 0;
    if (text == NULL) {
        return NULL;
    }
    for (i = 0; i < length; i++) {
        text[i * 2] = digits[(bytes[i] >> 4) & 15];
        text[i * 2 + 1] = digits[bytes[i] & 15];
    }
    text[length * 2] = '\0';
    return text;
}

static unsigned char *jayess_openssl_required_bytes(jayess_value *value, const char *context, size_t *length_out) {
    const char *text = jayess_value_as_string(value);
    unsigned char *bytes = NULL;
    if (text != NULL) {
        char *copy = jayess_value_to_string_copy(value);
        if (copy == NULL) {
            jayess_throw_type_error(context);
            return NULL;
        }
        if (length_out != NULL) {
            *length_out = strlen(copy);
        }
        return (unsigned char *)copy;
    }
    bytes = jayess_value_to_bytes_copy(value, length_out);
    if (bytes == NULL && !jayess_has_exception()) {
        jayess_throw_type_error(context);
    }
    return bytes;
}

static jayess_value *jayess_openssl_required_option(jayess_object *options, const char *key, const char *context) {
    jayess_value *value = jayess_object_get(options, key);
    if (value == NULL || jayess_value_is_nullish(value)) {
        jayess_throw_type_error(context);
        return NULL;
    }
    return value;
}

static unsigned char *jayess_openssl_required_option_bytes(jayess_object *options, const char *key, const char *context, size_t *length_out) {
    jayess_value *value = jayess_openssl_required_option(options, key, context);
    if (jayess_has_exception()) {
        return NULL;
    }
    return jayess_openssl_required_bytes(value, context, length_out);
}

static unsigned char *jayess_openssl_optional_option_bytes(jayess_object *options, const char *key, const char *context, size_t *length_out) {
    jayess_value *value = jayess_object_get(options, key);
    if (length_out != NULL) {
        *length_out = 0;
    }
    if (value == NULL || jayess_value_is_nullish(value)) {
        return NULL;
    }
    return jayess_openssl_required_bytes(value, context, length_out);
}

jayess_value *jayess_openssl_random_bytes_native(jayess_value *length_value) {
    int length = (int)jayess_value_to_number(length_value);
    unsigned char *bytes = NULL;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    if (length < 0) {
        jayess_throw_type_error("jayess_openssl_random_bytes_native");
        return jayess_value_undefined();
    }
    bytes = (unsigned char *)malloc((size_t)length);
    if (bytes == NULL && length > 0) {
        jayess_throw_named_error("OpenSSLError", "failed to allocate random byte buffer");
        return jayess_value_undefined();
    }
    if (length > 0 && RAND_bytes(bytes, length) != 1) {
        free(bytes);
        jayess_throw_named_error("OpenSSLError", "OpenSSL random byte generation failed");
        return jayess_value_undefined();
    }
    {
        jayess_value *result = jayess_value_from_bytes_copy(bytes, (size_t)length);
        free(bytes);
        return result;
    }
}

jayess_value *jayess_openssl_version_native(void) {
    return jayess_value_from_string(OpenSSL_version(OPENSSL_VERSION));
}

jayess_value *jayess_openssl_supports_hash_native(jayess_value *algorithm_value) {
    const char *algorithm = jayess_expect_string(algorithm_value, "jayess_openssl_supports_hash_native");
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    return jayess_value_from_bool(jayess_openssl_digest(algorithm) != NULL);
}

jayess_value *jayess_openssl_supports_cipher_native(jayess_value *algorithm_value) {
    const char *algorithm = jayess_expect_string(algorithm_value, "jayess_openssl_supports_cipher_native");
    size_t key_length = 0;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    return jayess_value_from_bool(jayess_openssl_cipher(algorithm, &key_length) != NULL);
}

jayess_value *jayess_openssl_hash_native(jayess_value *algorithm_value, jayess_value *value) {
    const char *algorithm = jayess_expect_string(algorithm_value, "jayess_openssl_hash_native");
    const EVP_MD *md = NULL;
    unsigned char *input = NULL;
    size_t input_length = 0;
    unsigned char digest[EVP_MAX_MD_SIZE];
    unsigned int digest_length = 0;
    char *hex = NULL;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    md = jayess_openssl_digest(algorithm);
    if (md == NULL) {
        jayess_throw_named_error("OpenSSLError", "unsupported OpenSSL digest algorithm");
        return jayess_value_undefined();
    }
    input = jayess_openssl_required_bytes(value, "jayess_openssl_hash_native", &input_length);
    if (jayess_has_exception()) {
        jayess_bytes_free(input);
        return jayess_value_undefined();
    }
    if (EVP_Digest(input, input_length, digest, &digest_length, md, NULL) != 1) {
        jayess_bytes_free(input);
        jayess_throw_named_error("OpenSSLError", "OpenSSL digest operation failed");
        return jayess_value_undefined();
    }
    jayess_bytes_free(input);
    hex = jayess_openssl_hex_encode(digest, (size_t)digest_length);
    if (hex == NULL) {
        jayess_throw_named_error("OpenSSLError", "failed to encode OpenSSL digest");
        return jayess_value_undefined();
    }
    {
        jayess_value *result = jayess_value_from_string(hex);
        free(hex);
        return result;
    }
}

jayess_value *jayess_openssl_hmac_native(jayess_value *algorithm_value, jayess_value *key_value, jayess_value *value) {
    const char *algorithm = jayess_expect_string(algorithm_value, "jayess_openssl_hmac_native");
    const EVP_MD *md = NULL;
    unsigned char *key = NULL;
    size_t key_length = 0;
    unsigned char *input = NULL;
    size_t input_length = 0;
    unsigned char digest[EVP_MAX_MD_SIZE];
    unsigned int digest_length = 0;
    char *hex = NULL;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    md = jayess_openssl_digest(algorithm);
    if (md == NULL) {
        jayess_throw_named_error("OpenSSLError", "unsupported OpenSSL HMAC algorithm");
        return jayess_value_undefined();
    }
    key = jayess_openssl_required_bytes(key_value, "jayess_openssl_hmac_native", &key_length);
    if (jayess_has_exception()) {
        jayess_bytes_free(key);
        return jayess_value_undefined();
    }
    input = jayess_openssl_required_bytes(value, "jayess_openssl_hmac_native", &input_length);
    if (jayess_has_exception()) {
        jayess_bytes_free(key);
        jayess_bytes_free(input);
        return jayess_value_undefined();
    }
    if (HMAC(md, key, (int)key_length, input, input_length, digest, &digest_length) == NULL) {
        jayess_bytes_free(key);
        jayess_bytes_free(input);
        jayess_throw_named_error("OpenSSLError", "OpenSSL HMAC operation failed");
        return jayess_value_undefined();
    }
    jayess_bytes_free(key);
    jayess_bytes_free(input);
    hex = jayess_openssl_hex_encode(digest, (size_t)digest_length);
    if (hex == NULL) {
        jayess_throw_named_error("OpenSSLError", "failed to encode OpenSSL HMAC");
        return jayess_value_undefined();
    }
    {
        jayess_value *result = jayess_value_from_string(hex);
        free(hex);
        return result;
    }
}

